/// Converter for handling null givenUserRoles in JSON
class GivenUserRolesConverter
    implements JsonConverter<Map<String, List<UserRole>>, Map<String, dynamic>?> {
  const GivenUserRolesConverter();

  @override
  Map<String, List<UserRole>> fromJson(Map<String, dynamic>? json) {
    if (json == null) return {};
    return json.map(
      (key, value) => MapEntry(
        key,
        (value as List<dynamic>)
            .map((e) => UserRole.fromJson(e as Map<String, dynamic>))
            .toList(),
      ),
    );
  }

  @override
  Map<String, dynamic> toJson(Map<String, List<UserRole>> object) {
    return object.map(
      (key, value) => MapEntry(
        key,
        value.map((e) => e.toJson()).toList(),
      ),
    );
  }
}

/// Converter for handling null accessibleContents in JSON
class AccessibleContentsConverter
    implements JsonConverter<UserAccessibleContents, Map<String, dynamic>?> {
  const AccessibleContentsConverter();

  @override
  UserAccessibleContents fromJson(Map<String, dynamic>? json) {
    return UserAccessContentsConverter.fromJson(json ?? {});
  }

  @override
  Map<String, dynamic> toJson(UserAccessibleContents object) {
    return object.toJson();
  }
}

