/// Converter for handling null givenUserRoles in JSON
class GivenUserRolesConverter
    implements JsonConverter<Map<String, List<UserRole>>, Object?> {
  const GivenUserRolesConverter();

  @override
  Map<String, List<UserRole>> fromJson(Object? json) {
    if (json == null) return {};
    final jsonMap = json as Map<String, dynamic>;
    return jsonMap.map(
      (key, value) => MapEntry(
        key,
        (value as List<dynamic>)
            .map((e) => UserRole.fromJson(e as Map<String, dynamic>))
            .toList(),
      ),
    );
  }

  @override
  Object toJson(Map<String, List<UserRole>> object) {
    return object.map(
      (key, value) => MapEntry(
