      _$UserAccessContentsToJson(_UserAccessContents(this))['data'];
}

@freezed
abstract class UserInfo with _$UserInfo {
  const UserInfo._();

  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory UserInfo({
    required String id,
    String? email,
    DateTime? deletedAt, // assumes UTC
    DateTime? createdAt, // assumes UTC
    DateTime? updatedAt, // assumes UTC
    required Profile profile,
    @AccessibleContentsConverter() @Default({}) UserAccessibleContents accessibleContents,
    @GivenUserRolesConverter() @Default({}) Map<String, List<UserRole>> givenUserRoles,
    required List<Team> teams,
  }) = _UserInfo;

  factory UserInfo.fromJson(Map<String, dynamic> json) {
      debugPrint('json: ${json}');
      return _$UserInfoFromJson(json);
  }

  bool isDeactivated(String? teamId) {
    if (teamId == null) return true;
    final roles = givenUserRoles[teamId];
    if (roles == null || roles.isEmpty) return true;
    // Check if the user has any active role in the team
    return roles.first.deleteFlag;
  }

  AppRole? getAppRoleFor(String teamId) {
    // First check for direct team assignment
    final directRole = givenUserRoles[teamId]?.firstOrNull?.roleGroup.name;
    if (directRole != null) {
      return directRole;
    }

    // For super_admin users, check if they have super_admin role for any team
    // If so, they should have super_admin privileges for all teams
    final hasSuperAdminRole = givenUserRoles.values
        .expand((roles) => roles)
        .any((userRole) => userRole.roleGroup.name == AppRole.superAdmin);
    if (hasSuperAdminRole) return AppRole.superAdmin;

    // For super readers, check if they have super_reader role for any team
    final hasSuperReaderRole = givenUserRoles.values
        .expand((roles) => roles)
        .any((userRole) => userRole.roleGroup.name == AppRole.superReader);
    if (hasSuperReaderRole) return AppRole.superReader;

    return null;
  }

  Team? getTeam(String teamId) {
    return teams.where((team) => team.id == teamId).firstOrNull;
  }

  bool isOnlyBelongingToSingleTeam() {
    // Filter out teams where the user is deactivated
    final activeTeams = teams.where((team) => !isDeactivated(team.id)).toList();

    if (activeTeams.length != 1) return false;
    final team = activeTeams.first;
    return team.isSingleUserTeam;
  }

  /// Returns true if the user has super_admin role for any team
  bool get isSuperAdmin {
    return givenUserRoles.values
        .expand((roles) => roles)
        .any((userRole) => userRole.roleGroup.name == AppRole.superAdmin);
  }

  /// Returns true if the user has super_reader role for any team
  bool get isSuperReader {
    return givenUserRoles.values
        .expand((roles) => roles)
        .any((userRole) => userRole.roleGroup.name == AppRole.superReader);
  }
}

